SELECT sample_id, genotype, quality_score
FROM tissue_samples
WHERE quality_score > 7;

SELECT sample_id, quality_score
FROM tissue_samples
WHERE quality_score > (SELECT AVG(quality_score) FROM tissue_samples);

SELECT DISTINCT genotype
FROM tissue_samples
ORDER BY genotype ASC;

SELECT version_number
FROM sample_versions
WHERE version_number > 1;
